import { localInputToISOWithOffset, utcToLocalInputValue } from '@linm-soft/common-components';
import type { CreatePurchaseInvoiceDto, PurchaseInvoiceDto } from '../../../../../services/kt/models';
import { resolveVoucherCurrencyFromDto } from '../../../../../utils/voucherCurrencyDefaults';
import type { PurchaseInvoiceLineRow } from '../types/purchaseInvoice.types';

/** `<input type="date">` requires YYYY-MM-DD (not datetime-local). */
export function toPurchaseInvoiceDateInputValue(value: string | null | undefined): string {
  if (!value) return '';
  const trimmed = value.trim();
  if (/^\d{4}-\d{2}-\d{2}$/.test(trimmed)) return trimmed;
  return utcToLocalInputValue(trimmed).slice(0, 10);
}

export interface PurchaseInvoiceSnapshot {
  invoiceDate: string;
  supplierId: string;
  supplierCode: string;
  supplierName: string;
  eInvoiceNo: string;
  description: string;
  currencyCode: string;
  exchangeRate: number;
  creditAccountCode: string;
  vatAccountCode: string;
  processingLevel: string;
  lines: PurchaseInvoiceLineRow[];
}

export function serializePurchaseInvoiceSnapshot(s: PurchaseInvoiceSnapshot): string {
  return JSON.stringify(s);
}

function dirtyPayload(s: PurchaseInvoiceSnapshot): string {
  return JSON.stringify({
    invoiceDate: s.invoiceDate,
    supplierId: s.supplierId,
    eInvoiceNo: s.eInvoiceNo,
    description: s.description,
    currencyCode: s.currencyCode,
    exchangeRate: Number(s.exchangeRate) || 1,
    creditAccountCode: s.creditAccountCode,
    vatAccountCode: s.vatAccountCode,
    processingLevel: s.processingLevel || '1',
    lines: s.lines.map(l => ({
      materialCode: l.materialCode,
      unitCode: l.unitCode,
      quantity: Number(l.quantity),
      unitPrice: Number(l.unitPrice),
      taxRate: Number(l.taxRate),
      debitAccountCode: l.debitAccountCode,
    })),
  });
}

export function purchaseInvoiceSnapshotsEqual(saved: string | null, current: string): boolean {
  if (!saved) return false;
  try {
    const a = JSON.parse(saved) as PurchaseInvoiceSnapshot;
    const b = JSON.parse(current) as PurchaseInvoiceSnapshot;
    return dirtyPayload(a) === dirtyPayload(b);
  } catch {
    return saved === current;
  }
}

export function buildSnapshotFromFields(input: {
  invoiceDate: string;
  supplierId: string;
  supplierCode: string;
  supplierName: string;
  eInvoiceNo: string;
  description: string;
  currencyCode: string;
  exchangeRate: number;
  creditAccountCode: string;
  vatAccountCode: string;
  processingLevel: string;
  lines: PurchaseInvoiceLineRow[];
}): PurchaseInvoiceSnapshot {
  return { ...input };
}

export function mapDtoToPurchaseInvoiceSnapshot(
  dto: PurchaseInvoiceDto,
  resolveUnitName: (code?: string) => string,
): PurchaseInvoiceSnapshot {
  return {
    invoiceDate: toPurchaseInvoiceDateInputValue(dto.invoiceDate),
    supplierId: dto.supplierId,
    supplierCode: '',
    supplierName: dto.supplierName ?? '',
    eInvoiceNo: dto.eInvoiceNo ?? '',
    description: dto.description ?? '',
    ...resolveVoucherCurrencyFromDto(dto.currencyCode, dto.exchangeRate),
    creditAccountCode: dto.creditAccountCode ?? '',
    vatAccountCode: dto.vatAccountCode ?? '',
    processingLevel: dto.processingLevel ?? '1',
    lines: dto.lines.map(l => ({
      materialCode: l.materialCode,
      materialName: l.materialName ?? '',
      unitCode: l.unitCode,
      unitName: l.unitName ?? resolveUnitName(l.unitCode),
      quantity: l.quantity,
      unitPrice: l.unitPrice,
      taxRate: l.taxRate,
      debitAccountCode: l.debitAccountCode,
      debitAccountName: l.debitAccountName ?? '',
    })),
  };
}

export const lineAmount = (l: PurchaseInvoiceLineRow) => Number(l.quantity) * Number(l.unitPrice);

export const lineTax = (l: PurchaseInvoiceLineRow) => lineAmount(l) * (Number(l.taxRate) / 100);

export function buildPurchaseInvoicePayload(
  invoiceDate: string,
  voucherCode: string,
  supplierId: string,
  eInvoiceNo: string,
  description: string,
  currencyCode: string,
  exchangeRate: number,
  creditAccountCode: string,
  vatAccountCode: string,
  processingLevel: string,
  lines: PurchaseInvoiceLineRow[],
): CreatePurchaseInvoiceDto {
  return {
    invoiceDate: localInputToISOWithOffset(invoiceDate),
    voucherCode,
    supplierId,
    eInvoiceNo: eInvoiceNo || undefined,
    description: description.trim() || undefined,
    currencyCode: currencyCode || undefined,
    exchangeRate: Number(exchangeRate) || 1,
    creditAccountCode,
    vatAccountCode,
    processingLevel: processingLevel.trim() || '1',
    lines: lines.map(l => {
      const amount = lineAmount(l);
      const taxAmount = lineTax(l);
      return {
        materialCode: l.materialCode,
        unitCode: l.unitCode,
        quantity: Number(l.quantity),
        unitPrice: Number(l.unitPrice),
        amount,
        taxRate: Number(l.taxRate),
        taxAmount,
        debitAccountCode: l.debitAccountCode,
      };
    }),
  };
}
